import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import axios from "../api/axios";
import toast from "react-hot-toast";

const Register = () => {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async e => {
    e.preventDefault();
    if (password.length < 6) { toast.error("Password must be at least 6 characters"); return; }
    try {
      setLoading(true);
      await axios.post("/auth/register", { name, email, password });
      toast.success("Account created! Please log in.");
      navigate("/login");
    } catch (err) {
      toast.error(err.response?.data?.message || "Registration failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">

      {/* LEFT SIDE - Thar Image */}
      <div className="auth-left">
        <img
          src="https://www.mahindra.com/resources/user-assets/SUV/thar/thar-home-banner.jpg"
          alt="Mahindra Thar"
          onError={e => {
            e.target.style.display = "none";
          }}
          style={{
            position: "absolute",
            inset: 0,
            width: "100%",
            height: "100%",
            objectFit: "cover",
            zIndex: 0,
          }}
        />
        <div className="auth-left-overlay">
          <p className="auth-quote"><em>Premium cars,</em><br />unbeatable prices.</p>
          <p style={{ color: "rgba(255,255,255,0.55)", fontSize: "0.88rem" }}>
            Start driving in under 2 minutes
          </p>
        </div>
      </div>

      {/* RIGHT SIDE - Form */}
      <div className="auth-right">
        <div className="auth-box">
          <div className="auth-logo" onClick={() => navigate("/")}>🚗 <span>Drive</span>Premium</div>
          <h1 className="auth-title">Create account</h1>
          <p className="auth-sub">Join DrivePremium and unlock our full fleet today.</p>

          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Full Name</label>
              <input type="text" placeholder="Rahul Sharma" value={name} onChange={e => setName(e.target.value)} required />
            </div>
            <div className="form-group">
              <label>Email</label>
              <input type="email" placeholder="you@example.com" value={email} onChange={e => setEmail(e.target.value)} required />
            </div>
            <div className="form-group">
              <label>Password</label>
              <input type="password" placeholder="Min. 6 characters" value={password} onChange={e => setPassword(e.target.value)} required />
            </div>
            <button type="submit" className="btn-primary btn-full" style={{ marginTop: 8 }} disabled={loading}>
              {loading ? "Creating account..." : "Create Account →"}
            </button>
          </form>

          <div className="auth-footer-link">
            Already have an account? <Link to="/login">Sign in</Link>
          </div>
        </div>
      </div>
    </div>
  );
};
export default Register;
